import * as React from 'react';
import { navigate } from 'gatsby';
import { useLocation } from '@gatsbyjs/reach-router';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import Divider from '@mui/material/Divider';
import IconButton from '@mui/material/IconButton';
import List from '@mui/material/List';
import ListItemButton from '@mui/material/ListItemButton';
import ListItemText from '@mui/material/ListItemText';
import SwipeableDrawer from '@mui/material/SwipeableDrawer';
import Typography from '@mui/material/Typography';
import MenuIcon from '@mui/icons-material/Menu';
import { Link } from './common/link';

const menuLists = [
  {
    label: 'Works',
    link: '/works/'
  },
  {
    label: 'Profile',
    link: '/profile/'
  },
  {
    label: 'Contact',
    link: '/contact/'
  },
  {
    label: '|',
    link: ''
  },
  {
    label: 'Instagram',
    link: 'https://www.instagram.com/yuheiono.photo/',
    isExternal: true
  }
];

export const Navigation = () => {
  const location = useLocation();

  const [isOpen, setIsOpen] = React.useState(false);

  const toggleDrawer = _isOpen => event => {
    if (
      event &&
      event.type === 'keydown' &&
      (event.key === 'Tab' || event.key === 'Shift')
    ) {
      return;
    }

    setIsOpen(_isOpen);
  };

  return (
    <AppBar
      position='fixed'
      sx={{
        backgroundColor: 'background.default',
        boxShadow: 'none'
      }}
    >
      <Container>
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            height: 80
          }}
        >
          <Box>
            <Link
              href='/'
              sx={{
                display: 'block'
              }}
            >
              <Typography
                sx={{
                  letterSpacing: '0.3rem'
                }}
              >
                YUHEI ONO
              </Typography>
            </Link>
          </Box>
          <Box display='flex'>
            {menuLists.map(({ label, link, isExternal }, i) => {
              let isCurrent = false;

              if (link === location.pathname) {
                isCurrent = true;
              }

              /*
              @TODO works 一覧をすばやく見れなくなるため一旦なしに

              else if (
                !!location.pathname.match(/^(\/works\/)/) &&
                link === '/works/'
              ) {
                // works の詳細ページ対応
                isCurrent = true;
              }
              */

              return link ? (
                <Link
                  key={i}
                  href={link}
                  // target={isExternal && '_blank'}
                  sx={{
                    ml: '1.5rem',
                    display: {
                      xs: 'none',
                      md: 'block'
                    },
                    textDecoration: isCurrent && 'underline',
                    pointerEvents: isCurrent && 'none'
                  }}
                >
                  <Typography
                    variant='body2'
                    sx={{
                      letterSpacing: '0.1rem'
                    }}
                  >
                    {label}
                  </Typography>
                </Link>
              ) : (
                <Typography
                  key={i}
                  variant='body2'
                  sx={{
                    pointerEvents: 'none',
                    ml: '1rem',
                    display: {
                      md: 'block',
                      xs: 'none'
                    }
                  }}
                >
                  {label}
                </Typography>
              );
            })}
            <IconButton
              aria-label='Open menu'
              role='button'
              onClick={toggleDrawer(true)}
              sx={{
                display: {
                  xs: 'block',
                  md: 'none'
                }
              }}
            >
              <MenuIcon />
            </IconButton>
          </Box>
        </Box>
      </Container>
      <SwipeableDrawer
        anchor='right'
        open={isOpen}
        onClose={toggleDrawer(false)}
        onOpen={toggleDrawer(true)}
      >
        <Box
          sx={{
            width: 200,
            height: '100%'
          }}
          role='presentation'
          onClick={toggleDrawer(false)}
          onKeyDown={toggleDrawer(false)}
        >
          <List>
            {menuLists.map(({ label, link, isExternal }, i) =>
              link ? (
                <ListItemButton
                  key={i}
                  href={link}
                  target={isExternal && '_blank'}
                  onClick={e => {
                    if (!isExternal) {
                      e.preventDefault();
                      navigate(link);
                    }
                  }}
                >
                  <ListItemText>{label}</ListItemText>
                </ListItemButton>
              ) : (
                <Divider key={i} />
              )
            )}
          </List>
        </Box>
      </SwipeableDrawer>
    </AppBar>
  );
};
